                    $footer  = "===END:$($Case.Name)==="
                    $exitLn  = "EXITCODE=$exit"
                    Add-Content -LiteralPath $script:ActResult -Value $header
                    Add-Content -LiteralPath $script:ActResult -Value $exitLn
                    Add-Content -LiteralPath $script:ActResult -Value $output
                    Add-Content -LiteralPath $script:ActResult -Value $footer

                    return [pscustomobject]@{ Exit = $exit; Output = $output }
